executeFunc((function executeOrderCanvasSublitForm(){const myOffcanvas=document.getElementById("offcanvas");const forms=myOffcanvas.querySelector("form");if(typeof forms!=="object"){return false}submitOrderCanvasForm(forms);return true}));async function submitOrderCanvasForm(forms){let order_submit_btn=document.getElementById(forms.name+"_order");if(typeof order_submit_btn=="object"){forms.addEventListener("submit",(function(event){event.preventDefault();disabledElementsForm(forms);const data=new FormData(forms);fetch(forms.action,{method:forms.method,cache:"no-cache",credentials:"same-origin",headers:{"X-Requested-With":"XMLHttpRequest"},redirect:"follow",referrerPolicy:"no-referrer",body:data}).then((response=>{if(!response.ok){throw new Error(`Ошибка HTTP: ${response.status}`)}return response.json()})).then((data=>{createToast(data);const order_card=document.getElementById(forms.dataset.id);if(order_card){const label=order_card.querySelector(`label[for="${forms.dataset.posting}"]`);let draggable=order_card.querySelector('[class*="draggable"]');if(draggable!==null){let draggableMove=draggable.querySelector(".bi-arrows-move");draggableMove.classList.add("d-none");let draggableLock=draggable.querySelector(".bi-ban");draggableLock.classList.remove("d-none");label?.classList.add("fade");draggable.classList.remove("draggable-handle");draggable.classList.add("draggable-lock")}}var myOffcanvas=document.getElementById("offcanvas");if(myOffcanvas){let bsOffcanvas=bootstrap.Offcanvas.getOrCreateInstance(myOffcanvas);bsOffcanvas.hide()}})).catch((error=>{let $successSupplyToast='{ "type":"danger" , '+'"header":"Ошибка при обновлении заказа"  , '+'"message" : "Повторите попытку позже либо обратитесь к администратору ресурса за дополнительной информацией" }';createToast(JSON.parse($successSupplyToast));var myOffcanvas=document.getElementById("offcanvas");if(myOffcanvas){let bsOffcanvas=bootstrap.Offcanvas.getOrCreateInstance(myOffcanvas);bsOffcanvas.hide()}}))}))}}